import{_ as s,C as o,o as l,c as n,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Slovakia Healthcare & HRT","description":"Transgender healthcare access in Slovakia","frontmatter":{"layout":"doc","title":"Slovakia Healthcare & HRT","description":"Transgender healthcare access in Slovakia"},"headers":[],"relativePath":"europe/slovakia/healthcare.md","filePath":"europe/slovakia/healthcare.md","lastUpdated":null}'),c={name:"europe/slovakia/healthcare.md"};function h(g,t,u,p,m,v){const e=o("Badge");return l(),n("div",null,[a(e,{variant:"red"},{default:i(()=>[...t[0]||(t[0]=[r("Gatekeeping Model",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[1]||(t[1]=[r("Only in Bratislava",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[2]||(t[2]=[r("Limited Providers",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="healthcare-hrt-in-slovakia" tabindex="-1">Healthcare &amp; HRT in Slovakia <a class="header-anchor" href="#healthcare-hrt-in-slovakia" aria-label="Permalink to &quot;Healthcare &amp; HRT in Slovakia&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Slovakia&#39;s transgender healthcare is <strong>limited to Bratislava</strong> with very few providers:</p><ul><li><strong>Psychiatric diagnosis required</strong> for access to HRT</li><li>Most services concentrated in <strong>Bratislava</strong> at major hospitals</li><li>Very few providers have experience with trans patients</li><li>Long wait times (6-12 months for initial appointment)</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-psychiatric-assessment" tabindex="-1">Step 1: Psychiatric Assessment <a class="header-anchor" href="#step-1-psychiatric-assessment" aria-label="Permalink to &quot;Step 1: Psychiatric Assessment&quot;">​</a></h3><ul><li>Contact <strong>Psychiatric Clinic of the Medical Faculty of Comenius University</strong> in Bratislava</li><li>Also possible at the <strong>Sexuology Department</strong> of the same institution</li><li>Diagnosis of gender dysphoria per ICD-10/11</li><li>Multiple sessions over 3-6 months</li><li>Very limited availability outside Bratislava</li></ul><h3 id="step-2-endocrinology-referral" tabindex="-1">Step 2: Endocrinology Referral <a class="header-anchor" href="#step-2-endocrinology-referral" aria-label="Permalink to &quot;Step 2: Endocrinology Referral&quot;">​</a></h3><ul><li>Referral to an endocrinologist for hormone therapy</li><li>Baseline blood tests required</li><li>HRT prescribed and monitored</li><li>Follow-up visits every 3-6 months</li></ul><h3 id="step-3-ongoing-care" tabindex="-1">Step 3: Ongoing Care <a class="header-anchor" href="#step-3-ongoing-care" aria-label="Permalink to &quot;Step 3: Ongoing Care&quot;">​</a></h3><ul><li>Regular monitoring by endocrinologist</li><li>Some GPs may manage ongoing HRT after specialist establishes treatment</li><li>Medications generally available at pharmacies</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Comenius University Psychiatric Clinic</td><td>Bratislava</td><td>Assessment, diagnosis</td></tr><tr><td>Comenius University Sexuology Department</td><td>Bratislava</td><td>Assessment, diagnosis</td></tr><tr><td>University Hospital Bratislava</td><td>Bratislava</td><td>Endocrinology</td></tr><tr><td>Private psychiatrists</td><td>Bratislava</td><td>Assessment (shorter waits)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Slovakia under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be re-evaluated by a Slovak doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Medication availability</strong>: Generally good in major cities</li><li><strong>Pharmacies</strong>: Major chains (Dr.Max, BENU) nationwide</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Slovakia domestically</li><li>The legal requirement for sterilization means surgery is required for legal recognition</li><li>Surgery must be sought abroad (Thailand, Germany, Serbia, Belgium)</li><li>No public funding for gender-affirming surgery</li><li>Previous providers in Slovakia have discontinued services</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Slovak Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Sexuology assessment (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Endocrinology visit (public)</td><td>Free</td><td>Limited access</td></tr><tr><td>Private psychiatrist</td><td>€40-80</td><td>€40-80</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€15-40</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.fmed.uniba.sk/" target="_blank" rel="noreferrer">Comenius University Psychiatric Clinic</a></li><li><a href="https://www.inakost.sk/" target="_blank" rel="noreferrer">Iniciatíva Inakosť (LGBTQ+ Organization)</a></li><li><a href="https://www.protiprudu.sk/" target="_blank" rel="noreferrer">Proti Prúdu (Trans Organization)</a></li><li><a href="https://www.health.gov.sk/" target="_blank" rel="noreferrer">Slovak Ministry of Health</a></li></ul>',21))])}const f=s(c,[["render",h]]);export{b as __pageData,f as default};
